{
  "model": "gpt-4.1-mini",
  "conversation": "${conv_id}",
  "input": [
    {
      "type": "message",
      "role": "developer",
      "content": "${wa_promt_gpt}\n${client_content}\nStyle rules:\n- Always respond in Argentinian Spanish\n- Keep responses concise, natural, ready to send\n- No markdown, no formatting, no links\n- Do not invent data\n- If critical info is missing -> offer transfer to human agent\n\nIf client insists on human -> call connect_to_agent\nIf conversation ends -> call return_final_status"
    },
    {
      "type": "message",
      "role": "user",
      "content": "${client_question}"
    }
  ],
  "tools": [
    {
      "type": "function",
      "name": "return_final_status",
      "description": "When the client has said goodbye, the issue is resolved, or you need to register the outcome of this turn, return the conversation result and classification.",
      "parameters": {
        "type": "object",
        "properties": {
          "client_response": {
            "type": "string",
            "description": "Short plain-text line suitable to send to the client in this turn (or empty if not applicable)."
          },
          "isFinal": {
            "type": "boolean",
            "description": "True if the client's interaction has ended for this conversation."
          },
          "contact_type": {
            "type": "string",
            "enum": ["contact_type_client", "third_party_contact"],
            "description": "Whether the conversation was with the client or with a third party. We always consider the dialogue with the client if we haven't received any feedback."
          },
          "promise_type": {
            "type": "string",
            "enum": [
              "promise_type_full_payment",
              "promise_type_partial_payment",
              "promise_type_discount",
              "promise_type_extension",
              "no_promise"
            ],
            "description": "promise_type_full_payment: client clearly promises to pay enough to close the loan. promise_type_partial_payment: only a partial payment promise. promise_type_discount: client accepts a discount offer. promise_type_extension: client accepts extension. no_promise: no payment promise was obtained in this turn."
          },
          "promise_date": {
            "type": "string",
            "enum": ["${cur_date}", "${tomorrow_dt}", ""],
            "description": "Only if the client explicitly promises to pay today or tomorrow: use ${cur_date} for today and ${tomorrow_dt} for tomorrow. Otherwise use empty string."
          },
          "promise_amount": {
            "type": "string",
            "enum": ["${amount}", "${extension_min_payment}", "${discount_payment}", ""],
            "description": "Amount the client promised to pay. Full loan closure -> ${amount}. Extension -> ${extension_min_payment}. Discounted amount when discount applies -> ${discount_payment}. If no amount promise -> empty string."
          },
          "contact_result": {
            "type": "string",
            "enum": [
              "contact_result_promise_of_payment",
              "contact_result_refusal_to_pay",
              "contact_result_already_payed",
              "contact_result_ptp_follow_up",
              "customer_with_current_agreement",
              "contact_result_paid_after_wa",
              "contact_result_provided_client_contact_info",
              "other",
              "contact_result_refusal_to_transfer_information"
            ],
            "description": "contact_result_promise_of_payment: clear promise to pay; date and amount are clear to the client. contact_result_refusal_to_pay: client refuses to promise payment. contact_result_already_payed: client says they already paid. contact_result_ptp_follow_up: client has an active promise and intends to fulfill it. customer_with_current_agreement: clarifying talk, no new debt position / ongoing handling. contact_result_paid_after_wa: client paid and notified after WhatsApp. contact_result_provided_client_contact_info: third party will pass contact to the client. contact_result_refusal_to_transfer_information: third party refuses to pass contact. other: none of the above."
          }
        },
        "required": [
          "client_response",
          "isFinal",
          "contact_type",
          "contact_result",
          "promise_type",
          "promise_date",
          "promise_amount"
        ]
      }
    },
    {
      "type": "function",
      "name": "connect_to_agent",
      "description": "Escalate to human agent",
      "parameters": {
        "type": "object",
        "properties": {
          "customer_request": {
            "type": "boolean"
          },
          "connect_to_agent": {
            "type": "boolean"
          }
        },
        "required": ["customer_request", "connect_to_agent"]
      }
    }
  ],
  "tool_choice": "auto"
}

