function isEmpty(v) {
  if (v === null || typeof v === "undefined") return true;
  var s = String(v).replace(/^\s+|\s+$/g, "");
  if (s === "") return true;
  if (s === "undefined" || s === "null") return true;
  return false;
}
function splitNames(raw) {
  if (isEmpty(raw)) return [];
  var parts = String(raw).split(",");
  var out = [];
  var i;
  var p;
  for (i = 0; i < parts.length; i++) {
    p = String(parts[i]).replace(/^\s+|\s+$/g, "");
    if (p !== "") out.push(p);
  }
  return out;
}
// ИМЯ переменной со списком — поменяй при необходимости
var listRaw = _getChannelVar("vars_to_check");
var names = splitNames(listRaw);
var firstEmpty = "";
var i;
var key;
var val;
if (names.length === 0) {
  return "vars_to_check_empty";
}
for (i = 0; i < names.length; i++) {
  key = names[i];
  val = _getChannelVar(key);
  if (isEmpty(val)) {
    firstEmpty = key;
    break;
  }
}
if (firstEmpty === "") {
  return "OK";
}
return firstEmpty;

