function val(name) {
  var v = _getChannelVar(name);
  if (v === null || typeof v === 'undefined') return '';
  var s = String(v).replace(/^\s+|\s+$/g, '');
  if (s === 'undefined' || s === 'null') return '';
  return s;
}

function line(label, name) {
  var v = val(name);
  if (v === '') return '';
  return label + v + '\n';
}

var msg = '';

msg += '⚠️ #' + val('company_name') + ' | #' + val('process_name') + '\n';
msg += '👤 ' + val('test_owner') + ' | 📞 ' + val('destination') + '\n';
msg += '📍 Stage: ' + val('stage') + '\n';

msg += '\n━━━ 🤖 OpenAI ━━━\n';
