msg += line('Call type: ', 'crm_call_type');
msg += line('Phone: ', 'destination');

msg += '\n━━━ 🔧 CRM ━━━\n';
msg += line('Status: ', 'status');
msg += line('Message: ', 'message');
msg += line('CRM code: ', 'CRM_response_code_result');

var chatLog = val('chat_log');
if (chatLog !== '') {
  msg += '\n━━━ 💬 Chat log ━━━\n';
